-- ----------------------------
-- Table structure for t_end_user
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user`;
CREATE TABLE `t_end_user`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `avatar` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '头像',
  `account` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '账号(登录账号)',
  `password` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '密码MD5值',
  `salt` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '盐值',
  `name` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '昵称',
  `dob` datetime NULL DEFAULT NULL COMMENT '生日',
  `gender` smallint NULL DEFAULT NULL COMMENT '性别:0-男,1-女,2-保密',
  `email` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '邮箱',
  `phone` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '电话',
  `invite_code` varchar(32) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '专属邀请码',
  `invitor_id` bigint NULL DEFAULT NULL COMMENT '邀请人id',
  `status` int NULL DEFAULT 0 COMMENT '状态',
  `team_count` int NULL DEFAULT 1 COMMENT '团队人数',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间，可理解为注册时间',
  `version` int NULL DEFAULT NULL COMMENT '版本',
  `delete_flag` int NOT NULL DEFAULT 0 COMMENT '逻辑删除字段',
  `registered_github_username` varchar(40) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '注册的github用户名',
  `registered_phone` varchar(20) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '注册手机',
  `registered_email` varchar(40) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '注册EMAIL',
  `email_validated` tinyint NOT NULL DEFAULT 0 COMMENT '邮箱是否验证，默认 0-未验证,1-验证',
  `phone_validated` tinyint NOT NULL DEFAULT 0 COMMENT '电话是否验证，默认 0-未验证,1-验证',
  `org_id` bigint UNSIGNED NOT NULL DEFAULT 1 COMMENT '部门 id ',
  `tag` varchar(30) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL DEFAULT 'NORMAL' COMMENT '分类字段',
  `category_tag` varchar(30) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '分类字段2',
  `is_compere` smallint NOT NULL DEFAULT 0 COMMENT '是否是主持人，0否1是',
  `is_register` smallint NOT NULL DEFAULT 0 COMMENT '是否是注册用户，0否1是',
  `type` int NULL DEFAULT 0 COMMENT '类型 1 普通用户 2供应商 3是租户 4房东 5中介 7是运维 8体验用户',
  `sys_user_id` bigint NULL DEFAULT NULL COMMENT '关联系统用户id',
  `vendor` varchar(40) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '用户所属渠道',
  `org_update_time` datetime NULL DEFAULT NULL,
  `property_consultant` tinyint NULL DEFAULT 0 COMMENT '是否是置业顾问 默认0不是 1-是',
  `produce_team` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '经济社',
  `team_id` bigint NULL DEFAULT NULL,
  `agent_id` bigint NULL DEFAULT NULL COMMENT '绑定代理',
  `appid` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `current_org_id` bigint NULL DEFAULT NULL COMMENT '当前组织id',
  `union_id` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '唯一应用id',
  `wx_code` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '微信号',
  `real_name` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL,
  `invitor_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '强弱绑定',
  `third_union_id` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '第三方union',
  `last_login_time` datetime NULL DEFAULT NULL COMMENT '最后登录时间',
  `shield` tinyint NULL DEFAULT NULL COMMENT '是否被拉黑',
  `id_card` varchar(18) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '身份证号',
  `id_card_font_imag` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '身份证号图片',
  `id_card_back_imag` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '身份证反面图片',
  `id_card_verify` tinyint NULL DEFAULT NULL COMMENT '身份验证状态 0-拒绝 1-同意 空未验证',
  `id_card_commit_time` datetime NULL DEFAULT NULL COMMENT '个人信息提交时间',
  `id_card_verify_time` datetime NULL DEFAULT NULL COMMENT '身份证验证时间',
  `commit_authentication_state` tinyint NULL DEFAULT 0 COMMENT '是否提交个人信息',
  `forever_admin` tinyint NULL DEFAULT 0 COMMENT '是否为永久管理员',
  `contact` varchar(11) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '销售工作电话',
  `company_account` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否是公司账号。 1：是， 0：不是',
  `organization_user` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否组织用户',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `account`(`account` ASC, `appid` ASC) USING BTREE,
  UNIQUE INDEX `phone`(`phone` ASC, `appid` ASC) USING BTREE,
  UNIQUE INDEX `registered_phone`(`registered_phone` ASC, `appid` ASC) USING BTREE,
  UNIQUE INDEX `registered_email`(`registered_email` ASC, `appid` ASC) USING BTREE,
  UNIQUE INDEX `registered_github_username`(`registered_github_username` ASC, `appid` ASC) USING BTREE,
  UNIQUE INDEX `email`(`email` ASC) USING BTREE,
  INDEX `id`(`id` ASC, `name` ASC) USING BTREE,
  INDEX `name`(`name` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3529 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of t_end_user
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_group
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_group`;
CREATE TABLE `t_end_user_group`  (
  `group_id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '小组ID',
  `group_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '小组名称',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '小组描述',
  `leader_id` bigint UNSIGNED NOT NULL COMMENT '小组负责人ID',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`group_id`) USING BTREE,
  INDEX `leader_id`(`leader_id` ASC) USING BTREE,
  CONSTRAINT `t_end_user_group_ibfk_1` FOREIGN KEY (`leader_id`) REFERENCES `t_end_user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '工作小组表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_group
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_group_relation
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_group_relation`;
CREATE TABLE `t_end_user_group_relation`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '关联ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `group_id` bigint UNSIGNED NOT NULL COMMENT '小组ID',
  `join_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '加入时间',
  `role_in_group` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '用户在小组中的角色（如成员、观察员）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `group_id`(`group_id` ASC) USING BTREE,
  CONSTRAINT `t_end_user_group_relation_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `t_end_user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `t_end_user_group_relation_ibfk_2` FOREIGN KEY (`group_id`) REFERENCES `t_end_user_group` (`group_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户小组关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_group_relation
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_position
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_position`;
CREATE TABLE `t_end_user_position`  (
  `position_id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '职位ID',
  `position_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '职位名称（唯一约束）',
  `department` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '所属部门',
  `parent_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT '上级职位ID（实现职位层级）',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`position_id`) USING BTREE,
  UNIQUE INDEX `position_name`(`position_name` ASC) USING BTREE,
  INDEX `parent_id`(`parent_id` ASC) USING BTREE,
  CONSTRAINT `t_end_user_position_ibfk_1` FOREIGN KEY (`parent_id`) REFERENCES `t_end_user_position` (`position_id`) ON DELETE SET NULL ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '组织职位表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_position
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_position_relation
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_position_relation`;
CREATE TABLE `t_end_user_position_relation`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '关联ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `position_id` bigint UNSIGNED NOT NULL COMMENT '职位ID',
  `start_date` date NULL DEFAULT NULL COMMENT '任职开始时间',
  `end_date` date NULL DEFAULT NULL COMMENT '任职结束时间（空值表示当前有效）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `position_id`(`position_id` ASC) USING BTREE,
  CONSTRAINT `t_end_user_position_relation_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `t_end_user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `t_end_user_position_relation_ibfk_2` FOREIGN KEY (`position_id`) REFERENCES `t_end_user_position` (`position_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户职位关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_position_relation
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_role
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_role`;
CREATE TABLE `t_end_user_role`  (
  `role_id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '角色ID',
  `role_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '角色名称（唯一约束）',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '角色描述',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`role_id`) USING BTREE,
  UNIQUE INDEX `role_name`(`role_name` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '系统角色表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_role
-- ----------------------------

-- ----------------------------
-- Table structure for t_end_user_role_relation
-- ----------------------------
DROP TABLE IF EXISTS `t_end_user_role_relation`;
CREATE TABLE `t_end_user_role_relation`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '关联ID',
  `user_id` bigint UNSIGNED NOT NULL COMMENT '用户ID',
  `role_id` bigint UNSIGNED NOT NULL COMMENT '角色ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `role_id`(`role_id` ASC) USING BTREE,
  CONSTRAINT `t_end_user_role_relation_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `t_end_user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `t_end_user_role_relation_ibfk_2` FOREIGN KEY (`role_id`) REFERENCES `t_end_user_role` (`role_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户角色关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_end_user_role_relation
-- ----------------------------

-- ----------------------------
-- Table structure for t_task_notes
-- ----------------------------
DROP TABLE IF EXISTS `t_task_notes`;
CREATE TABLE `t_task_notes`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `transfer_id` bigint NOT NULL COMMENT '任务ID（关联tasks.task_id）',
  `handler_id` bigint NOT NULL COMMENT '处理人ID（关联users.user_id）',
  `handler_name` varchar(26) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '处理人姓名（冗余存储，避免关联查询）',
  `from_status` varchar(26) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '处理前状态（如PENDING）',
  `to_status` varchar(26) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '处理后状态（如IN_PROGRESS）',
  `note` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '处理意见',
  `image_url` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '问题截图URL（如OSS路径）',
  `attachment` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '附件URL',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '记录创建时间',
  `status` varchar(26) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '处理状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`transfer_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '任务处理记录表（状态变更、意见、附件）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_task_notes
-- ----------------------------

-- ----------------------------
-- Table structure for t_task_transfers
-- ----------------------------
DROP TABLE IF EXISTS `t_task_transfers`;
CREATE TABLE `t_task_transfers`  (
  `transfer_id` bigint NOT NULL AUTO_INCREMENT COMMENT '流转记录唯一ID',
  `task_id` bigint NOT NULL COMMENT '任务ID（关联tasks.task_id）',
  `from_assignee_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '原负责人类型（USER:用户, ORGANIZATION:组织）',
  `from_assignee_id` bigint NOT NULL COMMENT '原负责人ID',
  `to_assignee_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '新负责人类型',
  `to_assignee_id` bigint NOT NULL COMMENT '新负责人ID',
  `transferred_by` bigint NOT NULL COMMENT '操作人ID（关联users.user_id）',
  `transferred_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '流转时间',
  `notes` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '流转备注（如转交原因）',
  PRIMARY KEY (`transfer_id`) USING BTREE,
  INDEX `task_id`(`task_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '任务流转记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_task_transfers
-- ----------------------------

-- ----------------------------
-- Table structure for t_tasks
-- ----------------------------
DROP TABLE IF EXISTS `t_tasks`;
CREATE TABLE `t_tasks`  (
  `task_id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务唯一ID',
  `title` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '任务标题',
  `attachment` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '附件URL（如OSS路径）',
  `image_url` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '问题截图URL（如OSS路径）',
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '任务详细描述',
  `status` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '任务状态（PENDING:待处理, IN_PROGRESS:进行中, COMPLETED:完成）',
  `priority` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '优先级（LOW:低, MEDIUM:中, HIGH:高）',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `deadline` datetime NULL DEFAULT NULL COMMENT '到期时间',
  `created_by` bigint NOT NULL COMMENT '创建人ID（关联users.user_id）',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '任务创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最后更新时间',
  `assignee_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '当前负责人类型（USER:用户, ORGANIZATION:组织）',
  `assignee_id` bigint NULL DEFAULT NULL COMMENT '当前负责人ID（根据类型关联users或organizations表）',
  `assignee_role` int NULL DEFAULT NULL COMMENT ' 如果是组织可以选择这个组织里面的角色',
  PRIMARY KEY (`task_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '任务主表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_tasks
-- ----------------------------

-- ----------------------------
-- Table structure for t_team
-- ----------------------------
DROP TABLE IF EXISTS `t_team`;
CREATE TABLE `t_team`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `team_name` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '团队名称',
  `team_desc` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '团队描述',
  `pid` bigint NULL DEFAULT NULL COMMENT '父级ID',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `teamName`(`team_name` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_team
-- ----------------------------

-- ----------------------------
-- Table structure for t_team_user
-- ----------------------------
DROP TABLE IF EXISTS `t_team_user`;
CREATE TABLE `t_team_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `teamId` bigint NOT NULL COMMENT '团队Id',
  `user_id` bigint NOT NULL COMMENT '员工ID',
  `isLeader` smallint NOT NULL DEFAULT 0 COMMENT '领导者(0-N 1-Y)',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of t_team_user
-- ----------------------------

-- ----------------------------
-- Table structure for task_process_relation
-- ----------------------------
DROP TABLE IF EXISTS `task_process_relation`;
CREATE TABLE `task_process_relation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '关联ID',
  `task_id` bigint NOT NULL COMMENT '任务ID，关联t_tasks.task_id',
  `process_id` bigint NOT NULL COMMENT '流程ID，关联wf_process.id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '任务-流程关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of task_process_relation
-- ----------------------------

-- ----------------------------
-- Table structure for wf_process
-- ----------------------------
DROP TABLE IF EXISTS `wf_process`;
CREATE TABLE `wf_process`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `current_user_id` bigint NULL DEFAULT NULL COMMENT '执行人id',
  `code` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '流程编码',
  `form_group` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '表单分组',
  `form_type` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '表单类型',
  `name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '流程名称',
  `category_id` bigint NULL DEFAULT NULL COMMENT '类别ID',
  `status` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '状态：ENABLED,DISABLED',
  `open_to` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL DEFAULT 'ALL' COMMENT '开放范围：ALL, DEPARTMENT, USER',
  `open_to_ids` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL COMMENT '指定开放部门或人员的id列表，逗号分隔',
  `org_id` bigint NULL DEFAULT NULL COMMENT '隔离标识',
  `code_rule` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '编号规则',
  `allow_delete` tinyint NULL DEFAULT 1 COMMENT '是否允许删除 1 允许 0 不允许',
  `process_type` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT 'PPROVAL（审批任务）, TRANSFER（流转任务）',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = DYNAMIC;

